+    contract.disqualifier_rules.precedence_order =
+        vec!["rule.second".to_string(), "rule.test_forbid".to_string()];
+    let errors = contract.validate().unwrap_err();
+    assert!(errors
+        .iter()
+        .any(|error| error.contains("precedence_order does not match")));
+}
