+        observation_interval_millionths: obs_us,
+        write_interval_millionths: write_us,
+        sample_count: 100,
+        measured_epoch: 0,
+    }
+}
+
+fn pair(fast: &str, slow: &str) -> ControllerPairId {
+    ControllerPairId {
