+    let expected = [
+        [true, true, true],   // from Unproven
+        [false, true, true],  // from Claimed
+        [false, false, true], // from Proven
+    ];
+    for (i, from) in states.iter().enumerate() {
+        for (j, to) in states.iter().enumerate() {
+            assert_eq!(
+                from.can_advance_to(*to),
